async function main() {
  const now = new Date();
  const MS_PER_DAY = 86400000;
  const input = $json.body || $json || {};

  const aliases = { java: 'java_dsa', dsa: 'java_dsa', java_dsa: 'java_dsa', dsa_java: 'java_dsa', python: 'python', flutter: 'flutter', sql: 'sql' };
  const labels = { java_dsa: 'Java DSA', python: 'Python', flutter: 'Flutter', sql: 'SQL' };
  const normalize = (v) => String(v || '').toLowerCase().trim().replace(/\s+/g, '_');

  const bank = {
    java_dsa: {
      foundation: ['Solve 3 easy array/string problems in Java.', 'Implement stack and queue with tests.', 'Practice binary search variants.'],
      intermediate: ['Solve 3 linked-list medium problems.', 'Practice 2 sliding-window questions.', 'Do recursion + backtracking set.'],
      project: ['Build a Java DSA tracker app.', 'Create BFS/DFS/template notes.', 'Take a 60-minute mock set.'],
      revision: ['Revise weak topics and retry failed questions.', 'Timed set: 1 easy, 2 medium, 1 hard.', 'Explain 5 DSA patterns aloud.']
    },
    python: {
      foundation: ['Revise core syntax and comprehensions.', 'Practice file + exception handling.', 'Solve 3 beginner Python problems.'],
      intermediate: ['Use collections in 3 coding tasks.', 'Practice OOP with dataclass.', 'Write 2 scripts and pytest tests.'],
      project: ['Build CLI study planner.', 'Use API data and summarize it.', 'Refactor script into modules.'],
      revision: ['Retry 3 mistakes from log.', 'Run a 45-minute coding sprint.', 'Create one-page Python cheat sheet.']
    },
    flutter: {
      foundation: ['Build responsive screen with core widgets.', 'Create validated form.', 'Practice multi-screen navigation.'],
      intermediate: ['Implement basic state management.', 'Consume REST API with states.', 'Build 2 reusable widgets.'],
      project: ['Build study progress app.', 'Add filter/progress UI.', 'Polish UX states and validation.'],
      revision: ['Review layout + state concepts.', 'Refactor one screen for reuse.', 'Prepare app demo walkthrough.']
    },
    sql: {
      foundation: ['Write 10 SELECT query drills.', 'Practice JOIN basics.', 'Solve GROUP BY and HAVING set.'],
      intermediate: ['Solve subquery + CTE set.', 'Practice window functions.', 'Design normalized schema.'],
      project: ['Create schema + seed + analysis queries.', 'Add indexes and compare speed.', 'Build weekly progress SQL report.'],
      revision: ['Retry difficult SQL questions.', 'Take timed SQL challenge.', 'Prepare compact SQL template notes.']
    }
  };

  const preferredMonths = Math.min(Math.max(Math.floor(Number(input.preferredMonths || $env.PREFERRED_MONTHS || 3)), 1), 24);
  const selectedRaw = Array.isArray(input.selectedCourses) ? input.selectedCourses.join(',') : (input.selectedCourses || $env.SELECTED_COURSES || 'java dsa,python,flutter,sql');
  const selected = [...new Set(String(selectedRaw).split(',').map((v) => aliases[normalize(v)] || normalize(v)).filter((c) => bank[c]))];
  const courses = selected.length ? selected : ['java_dsa', 'python', 'flutter', 'sql'];

  const startInput = input.studyPlanStartDate || $env.STUDY_PLAN_START_DATE;
  const parsedStart = startInput ? new Date(startInput) : now;
  const start = Number.isNaN(parsedStart.getTime()) ? new Date(now.getFullYear(), now.getMonth(), now.getDate()) : new Date(parsedStart.getFullYear(), parsedStart.getMonth(), parsedStart.getDate());
  const end = new Date(start);
  end.setMonth(end.getMonth() + preferredMonths);

  const totalDays = Math.max(1, Math.ceil((end.getTime() - start.getTime()) / MS_PER_DAY));
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  let dayNumber = Math.floor((today.getTime() - start.getTime()) / MS_PER_DAY) + 1;
  if (dayNumber < 1) dayNumber = 1;
  if (dayNumber > totalDays) dayNumber = totalDays;

  const phaseForDay = (d) => {
    const progress = (d - 1) / totalDays;
    if (progress >= 0.9) return 'revision';
    if (progress >= 0.7) return 'project';
    if (progress >= 0.35) return 'intermediate';
    return 'foundation';
  };

  const phase = phaseForDay(dayNumber);
  const phaseLabel = phase.charAt(0).toUpperCase() + phase.slice(1);

  const fallbackTasks = courses.map((course, idx) => {
    const list = bank[course][phase];
    return { course, courseLabel: labels[course], task: list[(dayNumber + idx * 3) % list.length] };
  });

  let tasks = fallbackTasks;
  let aiEnabled = false;
  let aiProvider = '';
  let aiCoachTip = '';

  const apiKey = $env.OPENAI_API_KEY || '';
  const model = $env.OPENAI_MODEL || 'gpt-4o-mini';
  const base = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1').replace(/\/$/, '');

  if (apiKey) {
    try {
      const prompt = [
        'You are a study planning agent.',
        `Courses: ${courses.map((c) => labels[c]).join(', ')}`,
        `Phase: ${phaseLabel}`,
        `Plan day: ${dayNumber}/${totalDays}`,
        'Return valid JSON only with keys tasks and coachTip.'
      ].join('\n');

      const res = await fetch(`${base}/chat/completions`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model,
          temperature: 0.5,
          response_format: { type: 'json_object' },
          messages: [
            { role: 'system', content: 'Return concise valid JSON.' },
            { role: 'user', content: prompt }
          ]
        })
      });

      if (res.ok) {
        const raw = await res.json();
        const content = raw?.choices?.[0]?.message?.content || '{}';
        const parsed = JSON.parse(content);
        const aiTasks = Array.isArray(parsed.tasks) ? parsed.tasks : [];

        if (aiTasks.length) {
          const byCourse = {};
          aiTasks.forEach((item) => {
            const c = aliases[normalize(item.course)] || normalize(item.course);
            const t = String(item.task || '').trim();
            if (courses.includes(c) && t && !byCourse[c]) byCourse[c] = t;
          });

          tasks = courses.map((course) => ({
            course,
            courseLabel: labels[course],
            task: byCourse[course] || fallbackTasks.find((x) => x.course === course).task
          }));

          aiEnabled = true;
          aiProvider = 'openai';
          aiCoachTip = String(parsed.coachTip || '').trim();
        }
      }
    } catch (e) {
      aiEnabled = false;
    }
  }

  const previewDays = [];
  for (let i = 0; i < 7; i += 1) {
    const d = new Date(today);
    d.setDate(d.getDate() + i);
    let n = Math.floor((d.getTime() - start.getTime()) / MS_PER_DAY) + 1;
    if (n < 1) n = 1;
    if (n > totalDays) n = totalDays;
    const p = phaseForDay(n);
    const c = courses[0];
    const l = bank[c][p];
    previewDays.push({
      date: d.toISOString().slice(0, 10),
      dateLabel: d.toLocaleDateString('en-GB', { weekday: 'short', day: '2-digit', month: 'short' }),
      phase: p,
      course: c,
      courseLabel: labels[c],
      task: l[n % l.length]
    });
  }

  const dateLabel = now.toLocaleDateString('en-GB', { weekday: 'long', day: '2-digit', month: 'short', year: 'numeric' });
  const planStart = start.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
  const planEnd = end.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

  const taskLines = tasks.map((t, i) => `${i + 1}) ${t.courseLabel}: ${t.task}`);
  const message = [
    `Daily Learning Tasks (${dateLabel})`,
    `${preferredMonths}-Month Course Plan: Day ${dayNumber}/${totalDays} | Phase: ${phaseLabel}`,
    `Plan Window: ${planStart} -> ${planEnd}`,
    `Selected Courses: ${courses.map((c) => labels[c]).join(', ')}`,
    '',
    ...taskLines,
    aiCoachTip ? `Coach Tip: ${aiCoachTip}` : '',
    '',
    'Target: 2-3 focused hours total.',
    'Rule: Finish at least one task per selected course.'
  ].filter(Boolean).join('\n');

  return [{
    json: {
      ok: true,
      subject: `Learning Plan Day ${dayNumber} - ${dateLabel}`,
      message,
      preferredMonths,
      selectedCourses: courses,
      dayNumber,
      totalDays,
      phase,
      planStart,
      planEnd,
      tasks,
      previewDays,
      aiEnabled,
      aiProvider,
      aiCoachTip
    }
  }];
}

return await main();

const payload = $json.body || $json;

const normalize = (value) => String(value || '').toLowerCase().trim().replace(/\s+/g, '_');
const alias = {
  java: 'java_dsa',
  dsa: 'java_dsa',
  java_dsa: 'java_dsa',
  dsa_java: 'java_dsa',
  python: 'python',
  flutter: 'flutter',
  sql: 'sql'
};

const courseInput = normalize(payload.course);
const course = alias[courseInput] || courseInput;
const validCourses = ['java_dsa', 'python', 'flutter', 'sql'];

if (!course || !validCourses.includes(course)) {
  return [{
    json: {
      ok: false,
      error: 'Invalid course. Use one of: java dsa, python, flutter, sql.'
    }
  }];
}

const status = normalize(payload.status || 'done');
if (!['done', 'in_progress', 'skip'].includes(status)) {
  return [{
    json: {
      ok: false,
      error: 'Invalid status. Use: done, in_progress, or skip.'
    }
  }];
}

const minutes = Number(payload.minutes || 0);
const note = String(payload.note || '').trim();
const now = new Date();
const dateKey = now.toISOString().slice(0, 10);
const timeKey = now.toISOString();

const staticData = getWorkflowStaticData('global');
if (!staticData.days) staticData.days = {};
if (!staticData.days[dateKey]) {
  staticData.days[dateKey] = {
    courses: {},
    totalMinutes: 0,
    events: []
  };
}

const day = staticData.days[dateKey];
if (!day.courses[course]) {
  day.courses[course] = { done: 0, in_progress: 0, skip: 0, minutes: 0 };
}

day.courses[course][status] += 1;
day.courses[course].minutes += Number.isFinite(minutes) && minutes > 0 ? minutes : 0;
day.totalMinutes += Number.isFinite(minutes) && minutes > 0 ? minutes : 0;

day.events.push({
  at: timeKey,
  course,
  status,
  minutes: Number.isFinite(minutes) && minutes > 0 ? minutes : 0,
  note
});

const selectedCourses = ($env.SELECTED_COURSES || 'java dsa,python,flutter,sql')
  .split(',')
  .map((value) => normalize(value))
  .map((value) => alias[value] || value)
  .filter((value) => validCourses.includes(value));

const uniqueSelected = [...new Set(selectedCourses.length ? selectedCourses : validCourses)];
const doneCourses = uniqueSelected.filter((key) => (day.courses[key]?.done || 0) > 0);
const completionPercent = Math.round((doneCourses.length / uniqueSelected.length) * 100);

const labels = { java_dsa: 'Java DSA', python: 'Python', flutter: 'Flutter', sql: 'SQL' };
const progressLines = uniqueSelected.map((key, idx) => {
  const stats = day.courses[key] || { done: 0, in_progress: 0, skip: 0, minutes: 0 };
  return `${idx + 1}) ${labels[key]} -> done:${stats.done}, in_progress:${stats.in_progress}, skip:${stats.skip}, minutes:${stats.minutes}`;
});

const message = [
  `Live Tracker Update (${dateKey})`,
  `Completion: ${completionPercent}% (${doneCourses.length}/${uniqueSelected.length} courses touched)`,
  `Total Focus Minutes: ${day.totalMinutes}`,
  '',
  ...progressLines
].join('\n');

return [{
  json: {
    ok: true,
    date: dateKey,
    updatedCourse: course,
    status,
    minutes: Number.isFinite(minutes) && minutes > 0 ? minutes : 0,
    note,
    completionPercent,
    message
  }
}];
